import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import StatsSection from './components/StatsSection';
import FilterSection from './components/FilterSection';
import StudentGrid from './components/StudentGrid';
import SettingsModal from './components/SettingsModal';
import StudentModal from './components/StudentModal';
import ProgressModal from './components/ProgressModal';
import { Student, FilterType, SortType } from './types';
import { SAMPLE_STUDENTS, STATIC_SCHOOL_MAP } from './constants';
import { parseFileName } from './utils/parsers';
import { imageDB, dataUrlToBlob } from './utils/db';

const App: React.FC = () => {
    // Data State
    const [students, setStudents] = useState<Student[]>([]);
    const [isLoaded, setIsLoaded] = useState(false);

    // UI State
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
    const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);

    // Progress Modal State
    const [isProgressOpen, setIsProgressOpen] = useState(false);
    const [progressCurrent, setProgressCurrent] = useState(0);
    const [progressTotal, setProgressTotal] = useState(0);

    // Filter State
    const [currentFilter, setCurrentFilter] = useState<FilterType>('all');
    const [schoolFilter, setSchoolFilter] = useState('all');
    const [weaponFilter, setWeaponFilter] = useState('all');
    const [sortFilter, setSortFilter] = useState<SortType>('default');
    const [searchTerm, setSearchTerm] = useState('');

    // Load Initial Data
    useEffect(() => {
        const stored = localStorage.getItem('blueArchiveStudents');
        if (stored) {
            try {
                let parsedStudents: Student[] = JSON.parse(stored);
                // Migration Logic
                parsedStudents = parsedStudents.map(s => ({
                    ...s,
                    costume: s.costume || 'default',
                    key: s.key || `${(s.name || '').toLowerCase()}__${(s.costume || 'default').toLowerCase()}`,
                    school: s.school || '',
                    affiliation: s.affiliation || '',
                    stars: s.stars || (s['blueStars' as keyof Student] ? `blue${s['blueStars' as keyof Student]}` : `yellow${s['yellowStars' as keyof Student] || 3}`)
                }));

                // Re-apply school map (incase static map updated)
                parsedStudents.forEach(s => {
                    const entry = STATIC_SCHOOL_MAP[s.name];
                    if (entry) {
                        s.school = entry.school;
                        s.affiliation = entry.affiliation;
                    }
                });

                setStudents(parsedStudents);
            } catch (e) {
                console.error("Failed to load students", e);
                setStudents([]);
            }
        } else {
            setStudents(SAMPLE_STUDENTS);
        }
        setIsLoaded(true);
    }, []);

    // Save Data
    useEffect(() => {
        if (isLoaded) {
            try {
                // We don't save image blob data to localstorage, only metadata
                const dataToSave = students.map(({ image, ...rest }) => rest);
                localStorage.setItem('blueArchiveStudents', JSON.stringify(dataToSave));
            } catch (e) {
                console.error("Storage full?", e);
                alert("保存に失敗しました。LocalStorageの容量が不足している可能性があります。");
            }
        }
    }, [students, isLoaded]);

    const handleLoadFiles = async (files: FileList) => {
        const fileList = Array.from(files).filter(f => f.name.toLowerCase().endsWith('.png'));
        if (fileList.length === 0) {
            alert('PNG画像が見つかりませんでした');
            return;
        }

        setIsSettingsOpen(false);
        setIsProgressOpen(true);
        setProgressTotal(fileList.length);
        setProgressCurrent(0);

        const newStudents = [...students];

        for (let i = 0; i < fileList.length; i++) {
            const file = fileList[i];
            const fileName = file.name.replace('.png', '');
            const { key, name, costume } = parseFileName(fileName);

            // Read file
            try {
                const buffer = await file.arrayBuffer();
                const blob = new Blob([buffer], { type: 'image/png' });

                // Store image in IndexedDB
                await imageDB.putImage(key, blob);

                const existingIndex = newStudents.findIndex(s => s.key === key);
                const schoolInfo = STATIC_SCHOOL_MAP[name] || { school: '', affiliation: '' };

                if (existingIndex > -1) {
                    newStudents[existingIndex] = {
                        ...newStudents[existingIndex],
                        imageId: key,
                        school: schoolInfo.school,
                        affiliation: schoolInfo.affiliation
                        // Keep other stats
                    };
                } else {
                    newStudents.push({
                        id: Date.now() + Math.random(),
                        key,
                        name,
                        costume,
                        school: schoolInfo.school,
                        affiliation: schoolInfo.affiliation,
                        imageId: key,
                        owned: false,
                        level: 1,
                        affection: 1,
                        stars: 'yellow3'
                    });
                }
            } catch (e) {
                console.error("Error processing file", file.name, e);
            }

            setProgressCurrent(i + 1);
            // Allow UI update
            await new Promise(r => setTimeout(r, 0)); 
        }

        setStudents(newStudents);
        setIsProgressOpen(false);
    };

    const handleClearData = async () => {
        if (confirm('すべてのデータを初期化してもよろしいですか？')) {
            setStudents([]);
            localStorage.removeItem('blueArchiveStudents');
            await imageDB.clear();
            setIsSettingsOpen(false);
        }
    };

    // Export Data (Backup)
    const handleExportData = () => {
        const dataStr = JSON.stringify(students, null, 2);
        const blob = new Blob([dataStr], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.download = `blue_archive_students_backup_${new Date().toISOString().slice(0, 10)}.json`;
        link.href = url;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    // Import Data (Restore)
    const handleImportData = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = e.target?.result as string;
                const parsedData = JSON.parse(json);
                if (Array.isArray(parsedData)) {
                    if (confirm('現在のデータを上書きしてバックアップを復元しますか？')) {
                        setStudents(parsedData);
                        alert('復元が完了しました。画像が表示されない場合は、再度画像を読み込んでください。');
                        setIsSettingsOpen(false);
                    }
                } else {
                    alert('無効なバックアップファイルです。');
                }
            } catch (error) {
                console.error('Import error:', error);
                alert('ファイルの読み込みに失敗しました。');
            }
        };
        reader.readAsText(file);
    };

    const handleToggleOwned = (student: Student) => {
        setStudents(prev => prev.map(s => s.id === student.id ? { ...s, owned: !s.owned } : s));
    };

    const handleStudentClick = (student: Student) => {
        setSelectedStudent(student);
        setIsStudentModalOpen(true);
    };

    const handleEditName = (student: Student) => {
        const newName = prompt('生徒名を入力してください:', student.name);
        if (newName && newName.trim() && newName !== student.name) {
            const trimmedName = newName.trim();
            const schoolEntry = STATIC_SCHOOL_MAP[trimmedName];

            setStudents(prev => prev.map(s => {
                if (s.id === student.id) {
                    return {
                        ...s,
                        name: trimmedName,
                        school: schoolEntry ? schoolEntry.school : s.school,
                        affiliation: schoolEntry ? schoolEntry.affiliation : s.affiliation
                    };
                }
                return s;
            }));
        }
    };

    const handleSaveStudent = (updatedStudent: Student) => {
        setStudents(prev => prev.map(s => s.id === updatedStudent.id ? updatedStudent : s));
    };

    const handleDeleteStudent = (student: Student) => {
        setStudents(prev => prev.filter(s => s.id !== student.id));
    };

    // Filtering logic
    const getFilteredStudents = () => {
        return students.filter(s => {
            // Owned Filter
            if (currentFilter === 'owned' && !s.owned) return false;
            if (currentFilter === 'unowned' && s.owned) return false;

            // School Filter
            if (schoolFilter !== 'all' && s.school !== schoolFilter) return false;

            // Weapon Filter
            const hasWeapon = s.stars && s.stars.startsWith('blue');
            if (weaponFilter === 'has' && !hasWeapon) return false;
            if (weaponFilter === 'none' && hasWeapon) return false;

            // Search
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                const matchesName = s.name.toLowerCase().includes(term);
                const matchesCostume = s.costume && s.costume.toLowerCase().includes(term);
                if (!matchesName && !matchesCostume) return false;
            }

            return true;
        });
    };

    const availableSchools = Array.from(new Set(students.map(s => s.school).filter(Boolean))).sort();

    return (
        <div className="max-w-[1400px] mx-auto p-5 pb-20">
            <Header onOpenSettings={() => setIsSettingsOpen(true)} />

            <main>
                <StatsSection students={students} />

                <FilterSection 
                    currentFilter={currentFilter}
                    setFilter={setCurrentFilter}
                    schoolFilter={schoolFilter}
                    setSchoolFilter={setSchoolFilter}
                    weaponFilter={weaponFilter}
                    setWeaponFilter={setWeaponFilter}
                    sortFilter={sortFilter}
                    setSortFilter={setSortFilter}
                    searchTerm={searchTerm}
                    setSearchTerm={setSearchTerm}
                    availableSchools={availableSchools}
                />

                <StudentGrid 
                    students={getFilteredStudents()} 
                    sortType={sortFilter}
                    onToggleOwned={handleToggleOwned}
                    onClick={handleStudentClick}
                    onEditName={handleEditName}
                />
            </main>

            <SettingsModal 
                isOpen={isSettingsOpen} 
                onClose={() => setIsSettingsOpen(false)} 
                onLoadFiles={handleLoadFiles}
                onClearData={handleClearData}
                onExportData={handleExportData}
                onImportData={handleImportData}
            />

            <StudentModal 
                isOpen={isStudentModalOpen}
                student={selectedStudent}
                onClose={() => setIsStudentModalOpen(false)}
                onSave={handleSaveStudent}
                onDelete={handleDeleteStudent}
            />

            <ProgressModal 
                isOpen={isProgressOpen}
                current={progressCurrent}
                total={progressTotal}
            />
        </div>
    );
};

export default App;

import React, { useRef } from 'react';
import { X, Image as ImageIcon, Folder, Trash2, Download, Upload } from 'lucide-react';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onLoadFiles: (files: FileList) => void;
    onClearData: () => void;
    onExportData: () => void;
    onImportData: (file: File) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ 
    isOpen, 
    onClose, 
    onLoadFiles, 
    onClearData,
    onExportData,
    onImportData
}) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const folderInputRef = useRef<HTMLInputElement>(null);
    const importInputRef = useRef<HTMLInputElement>(null);

    if (!isOpen) return null;

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onLoadFiles(e.target.files);
            e.target.value = ''; // Reset
        }
    };

    const handleImportChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onImportData(e.target.files[0]);
            e.target.value = ''; // Reset
        }
    };

    return (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-[#1a1a2e] rounded-2xl w-full max-w-lg shadow-2xl animate-[fadeIn_0.3s_ease] overflow-y-auto max-h-[90vh]">
                <div className="flex justify-between items-center p-5 border-b border-[#2c3e50]">
                    <h2 className="text-xl font-bold text-white m-0">設定</h2>
                    <button 
                        onClick={onClose}
                        className="bg-[#F44336] text-white border-none rounded-full w-10 h-10 flex items-center justify-center cursor-pointer transition-all duration-300 hover:bg-[#d32f2f] hover:scale-110"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>
                <div className="p-6">
                    <div className="mb-8">
                        <h3 className="text-lg text-white mb-4 border-l-4 border-[#4A90E2] pl-3">画像読み込み</h3>
                        <div className="flex flex-col gap-4">
                            <button 
                                onClick={() => fileInputRef.current?.click()}
                                className="flex items-center gap-3 px-6 py-3 border-none rounded-lg text-sm font-medium cursor-pointer transition-all text-white bg-gradient-to-r from-[#4A90E2] to-[#7B68EE] shadow-[0_4px_15px_rgba(74,144,226,0.3)] hover:-translate-y-0.5 justify-start w-full"
                            >
                                <ImageIcon className="w-5 h-5" />
                                画像を選択して読み込む
                            </button>
                            <button 
                                onClick={() => folderInputRef.current?.click()}
                                className="flex items-center gap-3 px-6 py-3 border-none rounded-lg text-sm font-medium cursor-pointer transition-all text-white bg-gradient-to-r from-[#4A90E2] to-[#7B68EE] shadow-[0_4px_15px_rgba(74,144,226,0.3)] hover:-translate-y-0.5 justify-start w-full"
                            >
                                <Folder className="w-5 h-5" />
                                フォルダごと読み込む
                            </button>
                        </div>
                    </div>

                    <div className="mb-8">
                         <h3 className="text-lg text-white mb-4 border-l-4 border-[#00B894] pl-3">バックアップと復元</h3>
                         <div className="flex flex-col gap-4">
                            <button 
                                onClick={onExportData}
                                className="flex items-center gap-3 px-6 py-3 border-none rounded-lg text-sm font-medium cursor-pointer transition-all text-white bg-[#00B894] hover:bg-[#00a884] shadow-[0_4px_15px_rgba(0,184,148,0.3)] hover:-translate-y-0.5 justify-start w-full"
                            >
                                <Download className="w-5 h-5" />
                                データを保存 (JSONダウンロード)
                            </button>
                            <button 
                                onClick={() => importInputRef.current?.click()}
                                className="flex items-center gap-3 px-6 py-3 border-none rounded-lg text-sm font-medium cursor-pointer transition-all text-white bg-[#2D3436] border border-[#636e72] hover:bg-[#353b48] justify-start w-full"
                            >
                                <Upload className="w-5 h-5" />
                                データを復元 (JSON読み込み)
                            </button>
                         </div>
                         <p className="text-xs text-[#b2bec3] mt-2 ml-1">
                             ※ ダウンロードしたJSONファイルをGoogle Drive等に保存してください。<br/>
                             ※ 画像データは含まれません。復元後に再度画像を読み込んでください。
                         </p>
                    </div>

                    <div>
                        <h3 className="text-lg text-white mb-4 border-l-4 border-[#F44336] pl-3">初期化</h3>
                        <button 
                            onClick={onClearData}
                            className="flex items-center gap-3 px-6 py-3 border-none rounded-lg text-sm font-medium cursor-pointer transition-all text-white bg-[#F44336]/20 border border-[#F44336] text-[#FF7675] hover:bg-[#F44336] hover:text-white justify-start w-full"
                        >
                            <Trash2 className="w-5 h-5" />
                            すべてのデータを削除
                        </button>
                    </div>
                </div>
            </div>

            <input 
                type="file" 
                ref={fileInputRef}
                accept="image/png" 
                multiple 
                className="hidden" 
                onChange={handleFileChange}
            />
            <input 
                type="file" 
                ref={folderInputRef}
                // @ts-ignore: webkitdirectory is standard in most browsers but not in React types
                webkitdirectory="" 
                directory="" 
                multiple 
                className="hidden" 
                onChange={handleFileChange}
            />
            <input 
                type="file" 
                ref={importInputRef}
                accept=".json" 
                className="hidden" 
                onChange={handleImportChange}
            />
        </div>
    );
};

export default SettingsModal;

